// Load the consolidated n8n/project-context.md once at workflow start.
// Every Stage-N builder later wraps this single string in <PROJECT_CONTEXT>
// at the top of its Claude CLI prompt.
//
// Source of truth: .claude/skills/ — the build script concatenates them
// into n8n/project-context.md. We run the script every workflow execution
// so live edits to any skill file flow straight into the next run.
//
// Why also cd /workspace before `claude -p`: CLAUDE.md auto-discovery is a
// fallback for project-level conventions not bundled in the skills.

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');
const projectPath = $json.projectPath;

// Auto-regenerate from .claude/skills/. Non-fatal if it fails (e.g. missing
// node in PATH, file lock) — we fall back to whatever is already on disk.
try {
  execSync('node scripts/build-project-context.js', { cwd: projectPath, stdio: 'pipe' });
} catch (e) {
  // Swallow — the read below either succeeds with stale content or throws.
}

const contextPath = path.join(projectPath, 'n8n', 'project-context.md');
if (!fs.existsSync(contextPath)) {
  throw new Error('n8n/project-context.md not found at ' + contextPath + '. Run `node scripts/build-project-context.js` once from the project root.');
}
const projectContext = fs.readFileSync(contextPath, 'utf8');

// Preserve upstream fields so downstream Drive nodes still have driveFolderId, etc.
return [{ json: { ...$json, projectContext } }];

// Group sibling files by module + slug + role (FSD / RSD / REQ).
// Filename convention: <module>__<slug>__<ROLE>.<ext>
// e.g. funds-transfer__internal-fx-transfer__FSD.md

const mod  = $('Set Config').first().json.module;
const slug = $('Set Config').first().json.featureSlug;
const files = $input.all().map(i => i.json);

const pick = (role) => {
  const rx = new RegExp(`^${mod}__${slug}__${role}\\.`, 'i');
  return files.find(f => rx.test(f.name)) || null;
};

const fsd = pick('FSD');
const rsd = pick('RSD');
const req = pick('REQ');

if (!fsd && !rsd && !req) {
  throw new Error(`No FSD/RSD/REQ siblings found for ${mod}__${slug}. Expected file names like ${mod}__${slug}__FSD.md`);
}

return [
  { json: { role: 'FSD',          fileId: fsd && fsd.id, fileName: fsd && fsd.name, mimeType: fsd && fsd.mimeType } },
  { json: { role: 'RSD',          fileId: rsd && rsd.id, fileName: rsd && rsd.name, mimeType: rsd && rsd.mimeType } },
  { json: { role: 'REQUIREMENTS', fileId: req && req.id, fileName: req && req.name, mimeType: req && req.mimeType } },
];

// Pass through the role + extracted text, dropping binary data.
const role = $('Pick FSD / RSD / REQ by slug').item.json.role;
const text = $json.text || $json.data || '';
return [{ json: { role, text } }];

// Collapse the 3-item merge into a single object with FSD/RSD/REQUIREMENTS text fields.
const cfg = $('Set Config').first().json;
const items = $input.all().map(i => i.json);
const byRole = Object.fromEntries(items.map(i => [i.role, i.text || '']));

const tsd = `<MODULE>${cfg.module}</MODULE>\n<FEATURE_SLUG>${cfg.featureSlug}</FEATURE_SLUG>\n\n<FSD>\n${byRole.FSD || ''}\n</FSD>\n\n<RSD>\n${byRole.RSD || ''}\n</RSD>\n\n<REQUIREMENTS>\n${byRole.REQUIREMENTS || ''}\n</REQUIREMENTS>`;

return [{ json: {
  module:         cfg.module,
  featureSlug:    cfg.featureSlug,
  projectPath:    cfg.projectPath,
  claudeModel:    cfg.claudeModel,
  jiraProjectKey: cfg.jiraProjectKey,
  fsdPresent:     !!(byRole.FSD || '').trim(),
  rsdPresent:     !!(byRole.RSD || '').trim(),
  reqPresent:     !!(byRole.REQUIREMENTS || '').trim(),
  tsd,
} }];

// Build a consolidated Stage-0 prompt and write it to /tmp/ for `claude -p` to read on stdin.
// The system text is kept in sync with n8n/prompts/v2-00-extract-requirements.md — edit there first, paste here.
const fs = require('fs');
const ctx = $('Load Project Context').first().json.projectContext;
const projectContextBlock = '<PROJECT_CONTEXT>\n' + ctx + '\n</PROJECT_CONTEXT>\n\n';

const system = `# System prompt — Stage 0: FSD + RSD + Requirements → structured feature digest

You are a senior business analyst on the Techlogix HBL OBDX 25.1 programme. You receive three documents for a single feature (FSD, RSD, Requirements) across any OBDX module (Trade Finance, Funds Transfer, Bill Payment, Reports, Bulk File Upload, Approvals, etc.) and produce one canonical, machine-readable digest that downstream prompts consume.

The <PROJECT_CONTEXT> block above is authoritative — when it disagrees with this prompt on terminology, module conventions, or test-data shape, the project context wins. Use it to ground every digest field.

Return ONLY a single fenced JSON code block matching the shape in n8n/prompts/v2-00-extract-requirements.md. No prose before or after.

Key rules:
- module field == <MODULE> input; feature_slug == <FEATURE_SLUG> input.
- Use the module-profile table in v2-00-extract-requirements.md to populate module_profile{ page_object_dir, fixture_name, test_data_file_hint, ... }.
- Quote system messages VERBATIM from the source.
- business_scenarios are cross-section multi-actor flows; single-field validations go in validation_rules.
- Conflicts between FSD and RSD: FSD is the system of record; record the conflict in open_questions.
- Multiple distinct features in the input → refuse via open_questions[0].`;

const slug = $('Set Config').first().json.featureSlug;
const promptPath = '/tmp/' + slug + '-stage0-prompt.md';
fs.writeFileSync(promptPath, projectContextBlock + system + '\n\n---\n\n' + $json.tsd, 'utf8');
return [{ json: { promptPath, slug } }];

// Extract the single fenced JSON block from the Claude CLI's stdout.
if ($json.exitCode !== 0) throw new Error('Stage 0: claude CLI exit ' + $json.exitCode + '\n' + ($json.stderr || ''));
const text = $json.stdout || '';
const m = text.match(/```json\s*([\s\S]*?)```/);
if (!m) throw new Error('Stage 0: no fenced JSON block in Claude response.\n\n' + text.slice(0, 500));
const digest = JSON.parse(m[1]);
return [{ json: { digest, digestRaw: m[1] } }];

// Resolve the canonical test-data file path (honour digest hint if present) and read existing contents.
const fs   = require('fs');
const path = require('path');
const projectPath = $('Set Config').first().json.projectPath;
const slug = $('Set Config').first().json.featureSlug;
const digest = $json.digest;

// Prefer digest.module_profile.test_data_file_hint; fall back to camelCased slug.
const camel = slug.replace(/-([a-z0-9])/g, (_, c) => c.toUpperCase());
const hinted = (digest.module_profile && digest.module_profile.test_data_file_hint) || ('data/' + camel + 'TestData.ts');
const dataFileName = path.basename(hinted);
const dataFilePath = path.isAbsolute(hinted) ? hinted : path.join(projectPath, hinted);

let existingContent = '';
let existingPresent = false;
if (fs.existsSync(dataFilePath)) {
  existingContent = fs.readFileSync(dataFilePath, 'utf8');
  existingPresent = true;
}

return [{ json: {
  digest,
  dataFileName,
  dataFilePath,
  existingContent,
  existingPresent,
} }];

// Stage-1: build the consolidated prompt and write to /tmp/.
const fs = require('fs');
const ctx = $('Load Project Context').first().json.projectContext;
const projectContextBlock = '<PROJECT_CONTEXT>\n' + ctx + '\n</PROJECT_CONTEXT>\n\n';

const system = `# System prompt — Stage 1: digest → test data file (append-mode, any OBDX module)

You produce a TypeScript test-data file for the Techlogix HBL OBDX 25.1 project. Output is a complete file at digest.module_profile.test_data_file_hint (typically data/<camelCasedSlug>TestData.ts) ready to be written to disk. Module-agnostic — same structural rules whether Trade Finance, Funds Transfer, Bill Payment, Reports, Bulk File Upload, etc.

Append-mode: if <EXISTING_FILE> is non-empty, preserve every existing key with its existing value verbatim, then add NEW keys produced from the digest. You may NOT delete or change existing values.

Return ONLY a single fenced TypeScript code block.

File shape (see n8n/prompts/v2-01-test-data.md for full template):
- JSDoc header citing the FSD/RSD references from the digest.
- export const <UPPER_SNAKE> = { ... } as const;
- export type <PascalCase> = typeof <UPPER_SNAKE>;
- Section banners // ── Section N — <label> ──...─ (use 'Tab' for trade-finance for parity).
- Login block with process.env.OBDX_USER / OBDX_PASSWORD fallback; add checker block if digest.actors has 2+ roles.
- Union types inline: as 'A' | 'B'.
- confirmationMessage and expectedStatus quoted VERBATIM from digest.system_messages.
- Negative-test data at the bottom, each commented with the rule it violates.
- Date format MM/DD/YYYY.
- No imports.`;

const userParts = [];
userParts.push('<DIGEST>\n' + JSON.stringify($json.digest, null, 2) + '\n</DIGEST>');
userParts.push('');
userParts.push('<EXISTING_FILE path="' + ('data/' + $json.dataFileName) + '">');
userParts.push($json.existingContent || '');
userParts.push('</EXISTING_FILE>');

const slug = $('Set Config').first().json.featureSlug;
const promptPath = '/tmp/' + slug + '-stage1-prompt.md';
fs.writeFileSync(promptPath, projectContextBlock + system + '\n\n---\n\n' + userParts.join('\n'), 'utf8');

return [{ json: { promptPath, dataFilePath: $json.dataFilePath, dataFileName: $json.dataFileName, digest: $json.digest } }];

// Extract the fenced ts block from CLI stdout and write it to disk.
const fs = require('fs');
const path = require('path');
if ($json.exitCode !== 0) throw new Error('Stage 1: claude CLI exit ' + $json.exitCode + '\n' + ($json.stderr || ''));
const text = $json.stdout || '';
const m = text.match(/```(?:ts|typescript)\s*([\s\S]*?)```/);
if (!m) throw new Error('Stage 1: no fenced TS block in Claude response.\n\n' + text.slice(0, 500));
const code = m[1];

const dataFilePath = $('Build Stage-1 Prompt').first().json.dataFilePath;
fs.mkdirSync(path.dirname(dataFilePath), { recursive: true });
fs.writeFileSync(dataFilePath, code, 'utf8');

return [{ json: {
  digest:        $('Build Stage-1 Prompt').first().json.digest,
  dataFilePath,
  dataFileName:  $('Build Stage-1 Prompt').first().json.dataFileName,
  dataFileContent: code,
} }];

// Stage-2: build the consolidated prompt and write to /tmp/.
const fs = require('fs');
const ctx = $('Load Project Context').first().json.projectContext;
const projectContextBlock = '<PROJECT_CONTEXT>\n' + ctx + '\n</PROJECT_CONTEXT>\n\n';

const system = `# System prompt — Stage 2: digest + test-data → OBDX 11-column test cases (any module, with business scenarios)

Return ONLY a single fenced JSON code block with shape:
{ module, feature, module_code, summary, test_data_const, test_cases: [...] }

Rules:
- TC-IDs: TC-<MODULE_CODE>-NNN section-scoped, TC-BS-NNN Business Scenarios (independent numbering).
- source_section values: "Section N — <label>" or literal "Business Scenarios". For trade-finance use "Tab N — <label>" for parity.
- category: Happy Path | Negative | Boundary | Edge | Business Scenario.
- priority P1 critical / P2 important / P3 nice-to-have. Every Business Scenario defaults to P1.
- Symbolic data refs: <CONST>.<key> for any value in the test-data file. Literals only when scenario hinges on them.
- Login + nav steps in every test_steps using digest.navigation_path.
- Quote digest.system_messages[].exact_text VERBATIM in expected_result.
- Wire digest.module_profile.module_specific_gotchas[] as explicit verification steps where they apply.
- Aim for 25-45 test cases for a typical 4-6 AC digest.
- Always include >=5 Business Scenario rows: maker-checker happy path, checker rejection, multi-actor data integrity, regulatory cross-tab edges. If digest.actors has multiple roles, every BS row names which actor performs which step.
- Add module-specific extras per v2-02-test-cases.md (FX-rate staleness for funds-transfer, biller-fetch failure for bill-payment, large-date-range for reports, file-format mismatch for bulk-file-upload, etc.).`;

const userParts = [];
userParts.push('<DIGEST>\n' + JSON.stringify($json.digest, null, 2) + '\n</DIGEST>');
userParts.push('');
userParts.push('<TEST_DATA path="data/' + $json.dataFileName + '">');
userParts.push($json.dataFileContent);
userParts.push('</TEST_DATA>');

const slug = $('Set Config').first().json.featureSlug;
const promptPath = '/tmp/' + slug + '-stage2-prompt.md';
fs.writeFileSync(promptPath, projectContextBlock + system + '\n\n---\n\n' + userParts.join('\n'), 'utf8');

return [{ json: { promptPath, dataFileName: $json.dataFileName, dataFileContent: $json.dataFileContent, digest: $json.digest } }];

// Parse the test-cases JSON from CLI stdout and stage it for HITL review.
const fs = require('fs');
const path = require('path');
if ($json.exitCode !== 0) throw new Error('Stage 2: claude CLI exit ' + $json.exitCode + '\n' + ($json.stderr || ''));
const text = $json.stdout || '';
const m = text.match(/```json\s*([\s\S]*?)```/);
if (!m) throw new Error('Stage 2: no fenced JSON block.\n\n' + text.slice(0, 500));
const cases = JSON.parse(m[1]);

const projectPath = $('Set Config').first().json.projectPath;
const slug = $('Set Config').first().json.featureSlug;
const stagingDir = path.join(projectPath, 'n8n', 'staging');
fs.mkdirSync(stagingDir, { recursive: true });
const stagingPath = path.join(stagingDir, slug + '-cases.json');
fs.writeFileSync(stagingPath, JSON.stringify(cases, null, 2), 'utf8');

return [{ json: {
  digest:           $('Build Stage-2 Prompt').first().json.digest,
  dataFileName:     $('Build Stage-2 Prompt').first().json.dataFileName,
  dataFileContent:  $('Build Stage-2 Prompt').first().json.dataFileContent,
  testCases:        cases,
  stagingPath,
  caseCount:        (cases.test_cases || []).length,
} }];

// Re-read the (possibly edited) test cases from disk so QA edits flow through.
const fs = require('fs');
const stagingPath = $('Parse + stage test cases').first().json.stagingPath;
const testCases = JSON.parse(fs.readFileSync(stagingPath, 'utf8'));
return [{ json: {
  digest:           $('Parse + stage test cases').first().json.digest,
  dataFileName:     $('Parse + stage test cases').first().json.dataFileName,
  dataFileContent:  $('Parse + stage test cases').first().json.dataFileContent,
  testCases,
  caseCount:        (testCases.test_cases || []).length,
} }];

// pipeline.md Stage 2 — locator scraper is MANDATORY before spec/POM generation.
// Skip the scrape ONLY if a scraped JSON already exists on disk (lets QA pre-scrape manually for tricky flows).
const fs   = require('fs');
const path = require('path');
const slug = $('Set Config').first().json.featureSlug;
const projectPath = $('Set Config').first().json.projectPath;
const scrapedPath = path.join(projectPath, 'data', 'scraped', slug + '-scraped.json');
const scrapedExists = fs.existsSync(scrapedPath);
return [{ json: { ...$json, scrapedPath, scrapedExists } }];

// Build the Stage-2.5 scraper-generation prompt.
// Reads the canonical scrape-view-outward-bg.js as a structural template.
const fs   = require('fs');
const path = require('path');
const ctx  = $('Load Project Context').first().json.projectContext;
const projectContextBlock = '<PROJECT_CONTEXT>\n' + ctx + '\n</PROJECT_CONTEXT>\n\n';

const projectPath = $('Set Config').first().json.projectPath;
const canonicalPath = path.join(projectPath, 'scripts', 'scrape-view-outward-bg.js');
const canonicalScraper = fs.existsSync(canonicalPath) ? fs.readFileSync(canonicalPath, 'utf8') : '// (canonical scraper not present — generate from first principles using the digest)';

const system = `# System prompt — Stage 2.5: digest + test cases → scripts/scrape-<slug>.js (Playwright DOM-locator scraper)

You generate a standalone Playwright Node script that drives the live OBDX AUT through ONE happy path, captures real DOM locators + values, and writes data/scraped/<feature_slug>-scraped.json. The downstream Stage 3 (Playwright spec + POM) reads ONLY this JSON — never the FSD or the digest — so this scrape is the source of truth for selectors.

Full rules in n8n/prompts/v2-04-scraper.md. Key points:
- Use require('playwright'), NOT @playwright/test. Standalone Node script.
- Read creds from process.env.OBDX_USER / OBDX_PASSWORD / BASE_URL (or OBDX_BASE_URL).
- Drive digest.navigation_path[] verbatim. For each tab, open every dropdown and capture every option + its literal id + stable fallback.
- Never use page.fill() on OJet inputs — use the native-setter + dispatch input/change/blur cycle (mirror canonical scraper helper).
- Headless by default (HEADED=1 to watch).
- On failure write partial JSON + process.exit(1) so the workflow halts.
- Output JSON shape: { env, feature, module, startedAt, finishedAt, url, menu[], tabs[{ index, label, literalId, fields[{ name, type, literalId, stableFallback, valueEntered, options, mandatory, errorText }] }], systemMessages{ successBanner, expectedStatus, referenceNumberLocator } }.

Return ONLY a single fenced JavaScript code block. No prose.`;

const userParts = [];
userParts.push('<DIGEST>\n' + JSON.stringify($json.digest, null, 2) + '\n</DIGEST>');
userParts.push('');
userParts.push('<TEST_CASES>\n' + JSON.stringify($json.testCases, null, 2) + '\n</TEST_CASES>');
userParts.push('');
userParts.push('<TEST_DATA path="data/' + $json.dataFileName + '">');
userParts.push($json.dataFileContent);
userParts.push('</TEST_DATA>');
userParts.push('');
userParts.push('<CANONICAL_SCRAPER path="scripts/scrape-view-outward-bg.js">');
userParts.push(canonicalScraper);
userParts.push('</CANONICAL_SCRAPER>');

const slug = $('Set Config').first().json.featureSlug;
const promptPath = '/tmp/' + slug + '-stage2-5-scraper-prompt.md';
fs.writeFileSync(promptPath, projectContextBlock + system + '\n\n---\n\n' + userParts.join('\n'), 'utf8');

return [{ json: { ...$json, promptPath } }];

// Extract the fenced JS block from CLI stdout and write to scripts/scrape-<slug>.js.
const fs   = require('fs');
const path = require('path');
if ($json.exitCode !== 0) throw new Error('Stage 2.5: claude CLI exit ' + $json.exitCode + '\n' + ($json.stderr || ''));
const text = $json.stdout || '';
const m = text.match(/```(?:js|javascript)\s*([\s\S]*?)```/);
if (!m) throw new Error('Stage 2.5: no fenced JS block in scraper-generation response.\n\n' + text.slice(0, 500));
const code = m[1];

const projectPath = $('Set Config').first().json.projectPath;
const slug = $('Set Config').first().json.featureSlug;
const scraperPath = path.join(projectPath, 'scripts', 'scrape-' + slug + '.js');
fs.mkdirSync(path.dirname(scraperPath), { recursive: true });
fs.writeFileSync(scraperPath, code, 'utf8');

return [{ json: {
  digest:          $('Build Scraper Prompt').first().json.digest,
  testCases:       $('Build Scraper Prompt').first().json.testCases,
  dataFileName:    $('Build Scraper Prompt').first().json.dataFileName,
  dataFileContent: $('Build Scraper Prompt').first().json.dataFileContent,
  scrapedPath:     $('Build Scraper Prompt').first().json.scrapedPath,
  scraperPath,
} }];

// Verify the scrape produced a JSON, then load it. Hard fail if missing.
// Reachable from two upstream paths (True branch skips the scrape; False branch ran it).
// Either way, 'Check Scraped JSON' ran upstream and carries the full data envelope.
const fs = require('fs');

// If we just came from Run Scraper, $json is { exitCode, stdout, stderr } —
// bail on non-zero before reading the JSON.
if (typeof $json.exitCode === 'number' && $json.exitCode !== 0) {
  throw new Error('Scraper exited with code ' + $json.exitCode + '. STDERR (last 2KB):\n' + ($json.stderr || '').slice(-2000));
}

const envelope = $('Check Scraped JSON').first().json;
const scrapedPath = envelope.scrapedPath;
if (!fs.existsSync(scrapedPath)) {
  throw new Error('Expected scraped JSON at ' + scrapedPath + ' but it is missing. Cannot proceed to Stage 3 with no locators.');
}
const scrapedJson = JSON.parse(fs.readFileSync(scrapedPath, 'utf8'));

return [{ json: {
  digest:          envelope.digest,
  testCases:       envelope.testCases,
  dataFileName:    envelope.dataFileName,
  dataFileContent: envelope.dataFileContent,
  scrapedJson,
  scrapedPath,
} }];

// Stage-3: build the consolidated prompt and write to /tmp/.
// Stage 3 emits TWO files: the spec AND the page object.
// Locators MUST come from <SCRAPED_LOCATORS> — never invented from the digest.
const fs = require('fs');
const ctx = $('Load Project Context').first().json.projectContext;
const projectContextBlock = '<PROJECT_CONTEXT>\n' + ctx + '\n</PROJECT_CONTEXT>\n\n';

const system = `# System prompt — Stage 3: test cases + test data + scraped locators → Playwright .spec.ts + page object

You produce TWO files in one response:
  1. The page object   at pages/<digest.module>/<digest.module_profile.page_object_class_hint>.ts
  2. The spec          at tests/<digest.module>/<digest.feature_slug>.spec.ts

## Output format — STRICT

Return TWO fenced TypeScript code blocks, each preceded by an exact "File: <path>" header. No prose between or around the blocks.

File: pages/<digest.module>/<digest.module_profile.page_object_class_hint>.ts
\`\`\`ts
// page object contents
\`\`\`

File: tests/<digest.module>/<digest.feature_slug>.spec.ts
\`\`\`ts
// spec contents
\`\`\`

The parser splits on /^File:\\s*([^\\n]+)\\n\\\`\\\`\\\`(?:ts|typescript)\\n/.

## Locator policy — NON-NEGOTIABLE

Every selector in the generated page object MUST be backed by an entry in <SCRAPED_LOCATORS>.
- Prefer the literalId for a unique match, with the stableFallback as a backup chain (\`page.locator('#literal').or(page.locator('[id^="prefix"]'))\`).
- For dropdowns: use the literalId of the dropdown trigger; option labels MUST come from scrapedJson.tabs[].fields[].options[].label verbatim.
- For mandatory fields: assertions of validation errors use scrapedJson.tabs[].fields[].errorText verbatim.
- If a test case references a field that does NOT appear in <SCRAPED_LOCATORS>: emit \`test.fixme(...)\` with a \`// TODO: re-scrape — field <name> not captured\` comment. Do NOT invent locators.

## Non-negotiable conventions (obdx-25.1-framework skill is authoritative — see PROJECT_CONTEXT)

- import { test, expect } from '@fixtures/auth.fixture' (NEVER @playwright/test).
- Path aliases @pages/* @utils/* @fixtures/* @config/* @data/*. No ../.. relative imports.
- test.describe.configure({ mode: 'serial' }) for section-progression and Business Scenario describes.
- Tags: @positive @negative @boundary @edge @business + @P1/P2/P3 + @regression + @<module>. For trade-finance also include per-tab tag (@tab1..@tab6).
- OJet inputs: NEVER page.fill() — use OjHelper.ojFill / ojFillDate from @utils/ojHelper.
- NEVER waitForLoadState('networkidle') — use WaitHelper.
- NEVER skip dashboardPage.waitForDashboard() before navigation.
- Page object structure: one class per flow, methods named after the action (fillTransferDetails, selectBiller, submit, assertConfirmation). Constructor takes (private page: Page). Export the class as default + named.
- Use <TEST_DATA_CONST>.<key> wherever the test cases reference symbolic data.
- Wire digest.module_profile.module_specific_gotchas[] into the appropriate POM method (FX-rate-wait, bill-fetch-wait, report-poll, file-upload two-step, etc.).
- Business Scenario rows requiring Maker→Checker switch open a fresh browser context for the checker.`;

const userParts = [];
userParts.push('<TEST_CASES>\n' + JSON.stringify($json.testCases, null, 2) + '\n</TEST_CASES>');
userParts.push('');
userParts.push('<TEST_DATA path="data/' + $json.dataFileName + '">');
userParts.push($json.dataFileContent);
userParts.push('</TEST_DATA>');
userParts.push('');
userParts.push('<DIGEST>\n' + JSON.stringify($json.digest, null, 2) + '\n</DIGEST>');
userParts.push('');
userParts.push('<SCRAPED_LOCATORS path="' + $json.scrapedPath + '">');
userParts.push(JSON.stringify($json.scrapedJson, null, 2));
userParts.push('</SCRAPED_LOCATORS>');

const slug = $('Set Config').first().json.featureSlug;
const promptPath = '/tmp/' + slug + '-stage3-prompt.md';
fs.writeFileSync(promptPath, projectContextBlock + system + '\n\n---\n\n' + userParts.join('\n'), 'utf8');

return [{ json: { promptPath, testCases: $json.testCases } }];

// Parse the Stage-3 multi-file response. Stage 3 emits TWO files:
//   1. The page object   at pages/<module>/<PascalCase>FlowPage.ts
//   2. The spec          at tests/<module>/<slug>.spec.ts
// Each file is announced by a 'File: <path>' header followed by a fenced ts block.
const fs = require('fs');
const path = require('path');
if ($json.exitCode !== 0) throw new Error('Stage 3: claude CLI exit ' + $json.exitCode + '\n' + ($json.stderr || ''));

const text = $json.stdout || '';
const projectPath = $('Set Config').first().json.projectPath;
const mod  = $('Set Config').first().json.module;
const slug = $('Set Config').first().json.featureSlug;

// Match every 'File: <path>\n```ts\n<body>\n```' block in order.
const fileBlockRegex = /^File:\s*([^\n]+)\n```(?:ts|typescript)\s*\n([\s\S]*?)```/gm;
const written = [];
let match;
while ((match = fileBlockRegex.exec(text)) !== null) {
  const relPath = match[1].trim();
  const code    = match[2];
  // Safety: only allow writes inside the project (no absolute paths, no ..).
  if (path.isAbsolute(relPath) || relPath.includes('..')) {
    throw new Error('Stage 3: refusing to write outside project: ' + relPath);
  }
  const absPath = path.join(projectPath, relPath);
  fs.mkdirSync(path.dirname(absPath), { recursive: true });
  fs.writeFileSync(absPath, code, 'utf8');
  written.push(relPath);
}

if (written.length < 2) {
  throw new Error('Stage 3: expected >= 2 File: blocks (POM + spec); got ' + written.length + '.\n\nFirst 800 chars of response:\n' + text.slice(0, 800));
}

const specRelative = written.find(p => /\.spec\.ts$/.test(p));
const pomRelative  = written.find(p => /FlowPage\.ts$/.test(p)) || written.find(p => /^pages\//.test(p));

if (!specRelative) throw new Error('Stage 3: no spec file (.spec.ts) in response. Got: ' + written.join(', '));
if (!pomRelative)  throw new Error('Stage 3: no page object (pages/...) in response. Got: ' + written.join(', '));

return [{ json: {
  projectPath,
  module:       mod,
  slug,
  specRelative,
  pomRelative,
  specPath:     path.join(projectPath, specRelative),
  pomPath:      path.join(projectPath, pomRelative),
  filesWritten: written,
} }];

// stdout is the JSON array of bug payloads.
const out = ($json.stdout || '').trim();
const bugs = out ? JSON.parse(out) : [];
if (!bugs.length) {
  return [{ json: { noFailures: true, count: 0 } }];
}
return bugs.map(b => ({ json: b }));

// For each Jira issue just created, build a list of {issueKey, filePath} pairs
// so the next loop can attach screenshot/trace/video.
const issueKey = $json.key;
const attachments = $('Parse bug payloads').itemMatching($itemIndex).json.attachments || [];
return attachments.map(p => ({ json: { issueKey, filePath: p } }));

// Final summary: roll up everything for the workflow response.
const writeSpec    = $('Write spec file').first().json;
const execTest     = $('Run Playwright suite').first().json;
const bugsRaw      = $('Parse bug payloads').all().map(i => i.json);
const jiraCreated  = $('Jira: Create Bug').all().map(i => i.json);

return [{ json: {
  status: 'ok',
  feature: writeSpec.slug,
  specPath: writeSpec.specPath,
  testDataPath: $('Build Stage-1 Prompt').first().json.dataFilePath,
  playwright: {
    exitCode: execTest.exitCode,
    stdoutTail: (execTest.stdout || '').slice(-2000),
  },
  customReport: $('Write spec file').first().json.projectPath + '/reports/custom-report.html',
  htmlReport:   $('Write spec file').first().json.projectPath + '/playwright-report/index.html',
  jira: {
    issuesCreated: jiraCreated.map(j => j.key).filter(Boolean),
    bugCount: bugsRaw.filter(b => !b.noFailures).length,
  },
} }];

// TSC failed branch — return the tsc output so QA can debug.
return [{ json: {
  status: 'error',
  stage: 'tsc-failed',
  message: 'Generated spec failed TypeScript compilation. Almost always a missing POM method — extend the page object or refine the Stage-3 prompt allow-list.',
  tsc_stdout: $json.stdout,
  tsc_stderr: $json.stderr,
  specPath: $('Write spec file').first().json.specPath,
} }];
